/// <remarks>
/// Micro air vehicle / autopilot classes. This identifies the individual model.
/// </remarks>
/// <summary>MAV_AUTOPILOT</summary>
public enum MavAutopilot {
  /// <remarks>
  /// Generic autopilot, full support for everything
  /// </remarks>
