  /// SLUGS autopilot, http://slugsuav.soe.ucsc.edu
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_SLUGS</summary>
  MAV_AUTOPILOT_SLUGS = 2,
  /// <remarks>
  /// ArduPilot - Plane/Copter/Rover/Sub/Tracker, https://ardupilot.org
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_ARDUPILOTMEGA</summary>
  MAV_AUTOPILOT_ARDUPILOTMEGA = 3,
  /// <remarks>
  /// OpenPilot, http://openpilot.org
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_OPENPILOT</summary>
  MAV_AUTOPILOT_OPENPILOT = 4,
  /// <remarks>
  /// Generic autopilot only supporting simple waypoints
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_GENERIC_WAYPOINTS_ONLY</summary>
  MAV_AUTOPILOT_GENERIC_WAYPOINTS_ONLY = 5,
  /// <remarks>
  /// Generic autopilot supporting waypoints and other simple navigation commands
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_GENERIC_WAYPOINTS_AND_SIMPLE_NAVIGATION_ONLY</summary>
  MAV_AUTOPILOT_GENERIC_WAYPOINTS_AND_SIMPLE_NAVIGATION_ONLY = 6,
  /// <remarks>
  /// Generic autopilot supporting the full mission command set
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_GENERIC_MISSION_FULL</summary>
  MAV_AUTOPILOT_GENERIC_MISSION_FULL = 7,
  /// <remarks>
  /// No valid autopilot, e.g. a GCS or other MAVLink component
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_INVALID</summary>
  MAV_AUTOPILOT_INVALID = 8,
  /// <remarks>
  /// PPZ UAV - http://nongnu.org/paparazzi
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_PPZ</summary>
  MAV_AUTOPILOT_PPZ = 9,
  /// <remarks>
  /// UAV Dev Board
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_UDB</summary>
  MAV_AUTOPILOT_UDB = 10,
  /// <remarks>
  /// FlexiPilot
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_FP</summary>
  MAV_AUTOPILOT_FP = 11,
  /// <remarks>
  /// PX4 Autopilot - http://px4.io/
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_PX4</summary>
  MAV_AUTOPILOT_PX4 = 12,
  /// <remarks>
  /// SMACCMPilot - http://smaccmpilot.org
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_SMACCMPILOT</summary>
  MAV_AUTOPILOT_SMACCMPILOT = 13,
  /// <remarks>
  /// AutoQuad -- http://autoquad.org
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_AUTOQUAD</summary>
  MAV_AUTOPILOT_AUTOQUAD = 14,
  /// <remarks>
  /// Armazila -- http://armazila.com
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_ARMAZILA</summary>
  MAV_AUTOPILOT_ARMAZILA = 15,
  /// <remarks>
  /// Aerob -- http://aerob.ru
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_AEROB</summary>
  MAV_AUTOPILOT_AEROB = 16,
  /// <remarks>
  /// ASLUAV autopilot -- http://www.asl.ethz.ch
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_ASLUAV</summary>
  MAV_AUTOPILOT_ASLUAV = 17,
  /// <remarks>
  /// SmartAP Autopilot - http://sky-drones.com
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_SMARTAP</summary>
  MAV_AUTOPILOT_SMARTAP = 18,
  /// <remarks>
  /// AirRails - http://uaventure.com
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_AIRRAILS</summary>
  MAV_AUTOPILOT_AIRRAILS = 19,
  /// <remarks>
  /// Fusion Reflex - https://fusion.engineering
  /// </remarks>
  /// <summary>MAV_AUTOPILOT_REFLEX</summary>
  MAV_AUTOPILOT_REFLEX = 20
}

public static class MavAutopilotExtensions {
  public static MavAutopilot FromValue(int value) {
    foreach (var member in Enum.GetValues<MavAutopilot>()) {
      if ((int)member == value) {
        return member;
      }
    }
    return Enum.GetValues<MavAutopilot>()[0];
  }
}

