  /// </remarks>
  /// <summary>MAV_COMP_ID_USER2</summary>
  MAV_COMP_ID_USER2 = 26,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
  /// </remarks>
  /// <summary>MAV_COMP_ID_USER3</summary>
  MAV_COMP_ID_USER3 = 27,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
  /// </remarks>
  /// <summary>MAV_COMP_ID_USER4</summary>
  MAV_COMP_ID_USER4 = 28,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
  /// </remarks>
  /// <summary>MAV_COMP_ID_USER5</summary>
  MAV_COMP_ID_USER5 = 29,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
  /// </remarks>
  /// <summary>MAV_COMP_ID_USER6</summary>
  MAV_COMP_ID_USER6 = 30,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
  /// </remarks>
  /// <summary>MAV_COMP_ID_USER7</summary>
  MAV_COMP_ID_USER7 = 31,
  /// <remarks>
  /// Id for a component on privately managed MAVLink network. Can be used for any purpose but may not be published by components outside of the private network.
