/// <remarks>
/// Flags to report failure cases over the high latency telemtry.
/// </remarks>
/// <summary>HL_FAILURE_FLAG</summary>
[Flags]
public enum HlFailureFlag {
  /// <remarks>
  /// GPS failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_GPS</summary>
  HL_FAILURE_FLAG_GPS = 1,
  /// <remarks>
  /// Differential pressure sensor failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE</summary>
  HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE = 2,
  /// <remarks>
  /// Absolute pressure sensor failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_ABSOLUTE_PRESSURE</summary>
  HL_FAILURE_FLAG_ABSOLUTE_PRESSURE = 4,
  /// <remarks>
  /// Accelerometer sensor failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_3D_ACCEL</summary>
  HL_FAILURE_FLAG_3D_ACCEL = 8,
  /// <remarks>
  /// Gyroscope sensor failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_3D_GYRO</summary>
  HL_FAILURE_FLAG_3D_GYRO = 16,
  /// <remarks>
  /// Magnetometer sensor failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_3D_MAG</summary>
  HL_FAILURE_FLAG_3D_MAG = 32,
  /// <remarks>
  /// Terrain subsystem failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_TERRAIN</summary>
  HL_FAILURE_FLAG_TERRAIN = 64,
  /// <remarks>
  /// Battery failure/critical low battery.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_BATTERY</summary>
  HL_FAILURE_FLAG_BATTERY = 128,
  /// <remarks>
  /// RC receiver failure/no rc connection.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_RC_RECEIVER</summary>
  HL_FAILURE_FLAG_RC_RECEIVER = 256,
  /// <remarks>
  /// Offboard link failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_OFFBOARD_LINK</summary>
  HL_FAILURE_FLAG_OFFBOARD_LINK = 512,
  /// <remarks>
  /// Engine failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_ENGINE</summary>
  HL_FAILURE_FLAG_ENGINE = 1024,
  /// <remarks>
  /// Geofence violation.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_GEOFENCE</summary>
  HL_FAILURE_FLAG_GEOFENCE = 2048,
  /// <remarks>
  /// Estimator failure, for example measurement rejection or large variances.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_ESTIMATOR</summary>
  HL_FAILURE_FLAG_ESTIMATOR = 4096,
  /// <remarks>
  /// Mission failure.
  /// </remarks>
  /// <summary>HL_FAILURE_FLAG_MISSION</summary>
  HL_FAILURE_FLAG_MISSION = 8192
}

public static class HlFailureFlagExtensions {
  public static HlFailureFlag FromValue(int value) {
    foreach (var member in Enum.GetValues<HlFailureFlag>()) {
      if ((int)member == value) {
        return member;
      }
    }
    var sorted = Enum.GetValues<HlFailureFlag>().Where(m => (int)m > 0).OrderByDescending(m => (int)m);
    foreach (var member in sorted) {
      if ((value & (int)member) != 0) {
        return member;
      }
    }
    foreach (var member in Enum.GetValues<HlFailureFlag>()) {
      if ((int)member == 0) {
        return member;
      }
    }
    return Enum.GetValues<HlFailureFlag>()[0];
  }
}

