/// <remarks>
/// Commands to be executed by the MAV. They can be executed on user request, or as part of a mission script. If the action is used in a mission, the parameter mapping to the waypoint/mission message is as follows: Param 1, Param 2, Param 3, Param 4, X: Param 5, Y:Param 6, Z:Param 7. This command list is similar what ARINC 424 is for commercial aircraft: A data format how to interpret waypoint/mission data. NaN and INT32_MAX may be used in float/integer params (respectively) to indicate optional/default values (e.g. to use the component's current yaw or latitude rather than a specific value). See https://mavlink.io/en/guide/xml_schema.html#MAV_CMD for information about the structure of the MAV_CMD entries
/// </remarks>
/// <summary>MAV_CMD</summary>
public enum MavCmd {
  /// <remarks>
  /// Navigate to waypoint.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_WAYPOINT</summary>
  MAV_CMD_NAV_WAYPOINT = 16,
  /// <remarks>
  /// Loiter around this waypoint an unlimited amount of time
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LOITER_UNLIM</summary>
  MAV_CMD_NAV_LOITER_UNLIM = 17,
  /// <remarks>
  /// Loiter around this waypoint for X turns
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LOITER_TURNS</summary>
  MAV_CMD_NAV_LOITER_TURNS = 18,
  /// <remarks>
  /// Loiter around this waypoint for X seconds
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LOITER_TIME</summary>
  MAV_CMD_NAV_LOITER_TIME = 19,
  /// <remarks>
  /// Return to launch location
  /// </remarks>
  /// <summary>MAV_CMD_NAV_RETURN_TO_LAUNCH</summary>
  MAV_CMD_NAV_RETURN_TO_LAUNCH = 20,
  /// <remarks>
  /// Land at location.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LAND</summary>
  MAV_CMD_NAV_LAND = 21,
  /// <remarks>
  /// Takeoff from ground / hand. Vehicles that support multiple takeoff modes (e.g. VTOL quadplane) should take off using the currently configured mode.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_TAKEOFF</summary>
  MAV_CMD_NAV_TAKEOFF = 22,
  /// <remarks>
  /// Land at local position (local frame only)
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LAND_LOCAL</summary>
  MAV_CMD_NAV_LAND_LOCAL = 23,
  /// <remarks>
  /// Takeoff from local position (local frame only)
  /// </remarks>
  /// <summary>MAV_CMD_NAV_TAKEOFF_LOCAL</summary>
  MAV_CMD_NAV_TAKEOFF_LOCAL = 24,
  /// <remarks>
  /// Vehicle following, i.e. this waypoint represents the position of a moving vehicle
  /// </remarks>
  /// <summary>MAV_CMD_NAV_FOLLOW</summary>
  MAV_CMD_NAV_FOLLOW = 25,
  /// <remarks>
  /// Continue on the current course and climb/descend to specified altitude.  When the altitude is reached continue to the next command (i.e., don't proceed to the next command until the desired altitude is reached.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_CONTINUE_AND_CHANGE_ALT</summary>
  MAV_CMD_NAV_CONTINUE_AND_CHANGE_ALT = 30,
  /// <remarks>
  /// Begin loiter at the specified Latitude and Longitude.  If Lat=Lon=0, then loiter at the current position.  Don't consider the navigation command complete (don't leave loiter) until the altitude has been reached. Additionally, if the Heading Required parameter is non-zero the aircraft will not leave the loiter until heading toward the next waypoint.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_LOITER_TO_ALT</summary>
  MAV_CMD_NAV_LOITER_TO_ALT = 31,
  /// <remarks>
  /// Begin following a target
  /// </remarks>
  /// <summary>MAV_CMD_DO_FOLLOW</summary>
  MAV_CMD_DO_FOLLOW = 32,
  /// <remarks>
  /// Reposition the MAV after a follow target command has been sent
  /// </remarks>
  /// <summary>MAV_CMD_DO_FOLLOW_REPOSITION</summary>
  MAV_CMD_DO_FOLLOW_REPOSITION = 33,
  /// <remarks>
  /// Sets the region of interest (ROI) for a sensor set or the vehicle itself. This can then be used by the vehicle's control system to control the vehicle attitude and the attitude of various sensors such as cameras.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_ROI</summary>
  MAV_CMD_NAV_ROI = 80,
  /// <remarks>
  /// Control autonomous path planning on the MAV.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_PATHPLANNING</summary>
  MAV_CMD_NAV_PATHPLANNING = 81,
  /// <remarks>
  /// Navigate to waypoint using a spline path.
  /// </remarks>
  /// <summary>MAV_CMD_NAV_SPLINE_WAYPOINT</summary>
  MAV_CMD_NAV_SPLINE_WAYPOINT = 82,
  /// <remarks>
