  /// </remarks>
  /// <summary>MAV_CMD_SET_RT_MODE_HID</summary>
  MAV_CMD_SET_RT_MODE_HID = 14501
}

public static class MavCmdExtensions {
  public static MavCmd FromValue(int value) {
    foreach (var member in Enum.GetValues<MavCmd>()) {
      if ((int)member == value) {
        return member;
      }
    }
    return Enum.GetValues<MavCmd>()[0];
  }
}

/// <remarks>
/// A data stream is not a fixed set of messages, but rather a
/// recommendation to the autopilot software. Individual autopilots may or may not obey
/// the recommended messages.
/// </remarks>
/// <summary>MAV_DATA_STREAM</summary>
public enum MavDataStream {
  /// <remarks>
  /// Enable all data streams
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_ALL</summary>
  MAV_DATA_STREAM_ALL = 0,
  /// <remarks>
  /// Enable IMU_RAW, GPS_RAW, GPS_STATUS packets.
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_RAW_SENSORS</summary>
  MAV_DATA_STREAM_RAW_SENSORS = 1,
  /// <remarks>
  /// Enable GPS_STATUS, CONTROL_STATUS, AUX_STATUS
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_EXTENDED_STATUS</summary>
  MAV_DATA_STREAM_EXTENDED_STATUS = 2,
  /// <remarks>
  /// Enable RC_CHANNELS_SCALED, RC_CHANNELS_RAW, SERVO_OUTPUT_RAW
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_RC_CHANNELS</summary>
  MAV_DATA_STREAM_RC_CHANNELS = 3,
  /// <remarks>
  /// Enable ATTITUDE_CONTROLLER_OUTPUT, POSITION_CONTROLLER_OUTPUT, NAV_CONTROLLER_OUTPUT.
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_RAW_CONTROLLER</summary>
  MAV_DATA_STREAM_RAW_CONTROLLER = 4,
  /// <remarks>
  /// Enable LOCAL_POSITION, GLOBAL_POSITION/GLOBAL_POSITION_INT messages.
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_POSITION</summary>
  MAV_DATA_STREAM_POSITION = 6,
  /// <remarks>
  /// Dependent on the autopilot
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_EXTRA1</summary>
  MAV_DATA_STREAM_EXTRA1 = 10,
  /// <remarks>
  /// Dependent on the autopilot
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_EXTRA2</summary>
  MAV_DATA_STREAM_EXTRA2 = 11,
  /// <remarks>
  /// Dependent on the autopilot
  /// </remarks>
  /// <summary>MAV_DATA_STREAM_EXTRA3</summary>
  MAV_DATA_STREAM_EXTRA3 = 12
}

public static class MavDataStreamExtensions {
  public static MavDataStream FromValue(int value) {
    foreach (var member in Enum.GetValues<MavDataStream>()) {
      if ((int)member == value) {
        return member;
      }
    }
    return Enum.GetValues<MavDataStream>()[0];
  }
}

/// <remarks>
/// The ROI (region of interest) for the vehicle. This can be
/// be used by the vehicle for camera/vehicle attitude alignment (see
/// MAV_CMD_NAV_ROI).
/// </remarks>
/// <summary>MAV_ROI</summary>
public enum MavRoi {
  /// <remarks>
  /// No region of interest.
  /// </remarks>
  /// <summary>MAV_ROI_NONE</summary>
  MAV_ROI_NONE = 0,
  /// <remarks>
  /// Point toward next waypoint, with optional pitch/roll/yaw offset.
  /// </remarks>
  /// <summary>MAV_ROI_WPNEXT</summary>
  MAV_ROI_WPNEXT = 1,
  /// <remarks>
  /// Point toward given waypoint.
  /// </remarks>
  /// <summary>MAV_ROI_WPINDEX</summary>
  MAV_ROI_WPINDEX = 2,
  /// <remarks>
  /// Point toward fixed location.
  /// </remarks>
  /// <summary>MAV_ROI_LOCATION</summary>
  MAV_ROI_LOCATION = 3,
