/// <remarks>
/// Bitmask of (optional) autopilot capabilities (64 bit). If a bit is set, the autopilot supports this capability.
/// </remarks>
/// <summary>MAV_PROTOCOL_CAPABILITY</summary>
[Flags]
public enum MavProtocolCapability {
  /// <remarks>
  /// Autopilot supports MISSION float message type.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT</summary>
  MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT = 1,
  /// <remarks>
  /// Autopilot supports the new param float message type.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_PARAM_FLOAT</summary>
  MAV_PROTOCOL_CAPABILITY_PARAM_FLOAT = 2,
  /// <remarks>
  /// Autopilot supports MISSION_ITEM_INT scaled integer message type.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_MISSION_INT</summary>
  MAV_PROTOCOL_CAPABILITY_MISSION_INT = 4,
  /// <remarks>
  /// Autopilot supports COMMAND_INT scaled integer message type.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_COMMAND_INT</summary>
  MAV_PROTOCOL_CAPABILITY_COMMAND_INT = 8,
  /// <remarks>
  /// Autopilot supports the new param union message type.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_PARAM_UNION</summary>
  MAV_PROTOCOL_CAPABILITY_PARAM_UNION = 16,
  /// <remarks>
  /// Autopilot supports the File Transfer Protocol v1: https://mavlink.io/en/services/ftp.html.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_FTP</summary>
  MAV_PROTOCOL_CAPABILITY_FTP = 32,
  /// <remarks>
  /// Autopilot supports commanding attitude offboard.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_SET_ATTITUDE_TARGET</summary>
  MAV_PROTOCOL_CAPABILITY_SET_ATTITUDE_TARGET = 64,
  /// <remarks>
  /// Autopilot supports commanding position and velocity targets in local NED frame.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_LOCAL_NED</summary>
  MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_LOCAL_NED = 128,
  /// <remarks>
  /// Autopilot supports commanding position and velocity targets in global scaled integers.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_GLOBAL_INT</summary>
  MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_GLOBAL_INT = 256,
  /// <remarks>
  /// Autopilot supports terrain protocol / data handling.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_TERRAIN</summary>
  MAV_PROTOCOL_CAPABILITY_TERRAIN = 512,
  /// <remarks>
  /// Autopilot supports direct actuator control.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_SET_ACTUATOR_TARGET</summary>
  MAV_PROTOCOL_CAPABILITY_SET_ACTUATOR_TARGET = 1024,
  /// <remarks>
  /// Autopilot supports the MAV_CMD_DO_FLIGHTTERMINATION command (flight termination).
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_FLIGHT_TERMINATION</summary>
  MAV_PROTOCOL_CAPABILITY_FLIGHT_TERMINATION = 2048,
  /// <remarks>
  /// Autopilot supports onboard compass calibration.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_COMPASS_CALIBRATION</summary>
  MAV_PROTOCOL_CAPABILITY_COMPASS_CALIBRATION = 4096,
  /// <remarks>
  /// Autopilot supports MAVLink version 2.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_MAVLINK2</summary>
  MAV_PROTOCOL_CAPABILITY_MAVLINK2 = 8192,
  /// <remarks>
  /// Autopilot supports mission fence protocol.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_MISSION_FENCE</summary>
  MAV_PROTOCOL_CAPABILITY_MISSION_FENCE = 16384,
  /// <remarks>
  /// Autopilot supports mission rally point protocol.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_MISSION_RALLY</summary>
  MAV_PROTOCOL_CAPABILITY_MISSION_RALLY = 32768,
  /// <remarks>
  /// Autopilot supports the flight information protocol.
  /// </remarks>
  /// <summary>MAV_PROTOCOL_CAPABILITY_FLIGHT_INFORMATION</summary>
  MAV_PROTOCOL_CAPABILITY_FLIGHT_INFORMATION = 65536
}

public static class MavProtocolCapabilityExtensions {
  public static MavProtocolCapability FromValue(int value) {
    foreach (var member in Enum.GetValues<MavProtocolCapability>()) {
      if ((int)member == value) {
        return member;
      }
    }
    var sorted = Enum.GetValues<MavProtocolCapability>().Where(m => (int)m > 0).OrderByDescending(m => (int)m);
    foreach (var member in sorted) {
      if ((value & (int)member) != 0) {
        return member;
      }
    }
    foreach (var member in Enum.GetValues<MavProtocolCapability>()) {
      if ((int)member == 0) {
        return member;
      }
    }
    return Enum.GetValues<MavProtocolCapability>()[0];
  }
}

