/// <summary>GPS_INPUT_IGNORE_FLAGS</summary>
[Flags]
public enum GpsInputIgnoreFlags {
  /// <remarks>
  /// ignore altitude field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_ALT</summary>
  GPS_INPUT_IGNORE_FLAG_ALT = 1,
  /// <remarks>
  /// ignore hdop field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_HDOP</summary>
  GPS_INPUT_IGNORE_FLAG_HDOP = 2,
  /// <remarks>
  /// ignore vdop field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_VDOP</summary>
  GPS_INPUT_IGNORE_FLAG_VDOP = 4,
  /// <remarks>
  /// ignore horizontal velocity field (vn and ve)
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_VEL_HORIZ</summary>
  GPS_INPUT_IGNORE_FLAG_VEL_HORIZ = 8,
  /// <remarks>
  /// ignore vertical velocity field (vd)
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_VEL_VERT</summary>
  GPS_INPUT_IGNORE_FLAG_VEL_VERT = 16,
  /// <remarks>
  /// ignore speed accuracy field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_SPEED_ACCURACY</summary>
  GPS_INPUT_IGNORE_FLAG_SPEED_ACCURACY = 32,
  /// <remarks>
  /// ignore horizontal accuracy field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_HORIZONTAL_ACCURACY</summary>
  GPS_INPUT_IGNORE_FLAG_HORIZONTAL_ACCURACY = 64,
  /// <remarks>
  /// ignore vertical accuracy field
  /// </remarks>
  /// <summary>GPS_INPUT_IGNORE_FLAG_VERTICAL_ACCURACY</summary>
  GPS_INPUT_IGNORE_FLAG_VERTICAL_ACCURACY = 128
}

public static class GpsInputIgnoreFlagsExtensions {
  public static GpsInputIgnoreFlags FromValue(int value) {
    foreach (var member in Enum.GetValues<GpsInputIgnoreFlags>()) {
      if ((int)member == value) {
        return member;
      }
    }
    var sorted = Enum.GetValues<GpsInputIgnoreFlags>().Where(m => (int)m > 0).OrderByDescending(m => (int)m);
    foreach (var member in sorted) {
      if ((value & (int)member) != 0) {
        return member;
      }
    }
    foreach (var member in Enum.GetValues<GpsInputIgnoreFlags>()) {
      if ((int)member == 0) {
        return member;
      }
    }
    return Enum.GetValues<GpsInputIgnoreFlags>()[0];
  }
}

/// <remarks>
/// Possible actions an aircraft can take to avoid a collision.
/// </remarks>
/// <summary>MAV_COLLISION_ACTION</summary>
public enum MavCollisionAction {
  /// <remarks>
  /// Ignore any potential collisions
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_NONE</summary>
  MAV_COLLISION_ACTION_NONE = 0,
  /// <remarks>
  /// Report potential collision
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_REPORT</summary>
  MAV_COLLISION_ACTION_REPORT = 1,
  /// <remarks>
  /// Ascend or Descend to avoid threat
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_ASCEND_OR_DESCEND</summary>
  MAV_COLLISION_ACTION_ASCEND_OR_DESCEND = 2,
  /// <remarks>
  /// Move horizontally to avoid threat
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_MOVE_HORIZONTALLY</summary>
  MAV_COLLISION_ACTION_MOVE_HORIZONTALLY = 3,
  /// <remarks>
  /// Aircraft to move perpendicular to the collision's velocity vector
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_MOVE_PERPENDICULAR</summary>
  MAV_COLLISION_ACTION_MOVE_PERPENDICULAR = 4,
  /// <remarks>
  /// Aircraft to fly directly back to its launch point
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_RTL</summary>
  MAV_COLLISION_ACTION_RTL = 5,
  /// <remarks>
  /// Aircraft to stop in place
  /// </remarks>
  /// <summary>MAV_COLLISION_ACTION_HOVER</summary>
  MAV_COLLISION_ACTION_HOVER = 6
}

public static class MavCollisionActionExtensions {
