  FOCUS_TYPE_AUTO_SINGLE = 5,
  /// <remarks>
  /// Continuous auto focus. Mainly used for dynamic scenes. Abbreviated as AF-C.
  /// </remarks>
  /// <summary>FOCUS_TYPE_AUTO_CONTINUOUS</summary>
  FOCUS_TYPE_AUTO_CONTINUOUS = 6
