/// <summary>GOPRO_HEARTBEAT_FLAGS</summary>
[Flags]
public enum GoproHeartbeatFlags {
  /// <remarks>
  /// GoPro is currently recording.
  /// </remarks>
  /// <summary>GOPRO_FLAG_RECORDING</summary>
  GOPRO_FLAG_RECORDING = 1
}

public static class GoproHeartbeatFlagsExtensions {
  public static GoproHeartbeatFlags FromValue(int value) {
    foreach (var member in Enum.GetValues<GoproHeartbeatFlags>()) {
      if ((int)member == value) {
        return member;
      }
    }
    var sorted = Enum.GetValues<GoproHeartbeatFlags>().Where(m => (int)m > 0).OrderByDescending(m => (int)m);
    foreach (var member in sorted) {
      if ((value & (int)member) != 0) {
        return member;
      }
    }
    foreach (var member in Enum.GetValues<GoproHeartbeatFlags>()) {
      if ((int)member == 0) {
        return member;
      }
    }
    return Enum.GetValues<GoproHeartbeatFlags>()[0];
  }
}

