/// <remarks>
/// Flags in EKF_STATUS message.
/// </remarks>
/// <summary>EKF_STATUS_FLAGS</summary>
[Flags]
public enum EkfStatusFlags {
  /// <remarks>
  /// Set if EKF's attitude estimate is good.
  /// </remarks>
  /// <summary>EKF_ATTITUDE</summary>
  EKF_ATTITUDE = 1,
  /// <remarks>
  /// Set if EKF's horizontal velocity estimate is good.
  /// </remarks>
  /// <summary>EKF_VELOCITY_HORIZ</summary>
  EKF_VELOCITY_HORIZ = 2,
  /// <remarks>
  /// Set if EKF's vertical velocity estimate is good.
  /// </remarks>
  /// <summary>EKF_VELOCITY_VERT</summary>
  EKF_VELOCITY_VERT = 4,
  /// <remarks>
  /// Set if EKF's horizontal position (relative) estimate is good.
  /// </remarks>
  /// <summary>EKF_POS_HORIZ_REL</summary>
  EKF_POS_HORIZ_REL = 8,
  /// <remarks>
  /// Set if EKF's horizontal position (absolute) estimate is good.
  /// </remarks>
  /// <summary>EKF_POS_HORIZ_ABS</summary>
  EKF_POS_HORIZ_ABS = 16,
  /// <remarks>
  /// Set if EKF's vertical position (absolute) estimate is good.
  /// </remarks>
  /// <summary>EKF_POS_VERT_ABS</summary>
  EKF_POS_VERT_ABS = 32,
  /// <remarks>
  /// Set if EKF's vertical position (above ground) estimate is good.
  /// </remarks>
  /// <summary>EKF_POS_VERT_AGL</summary>
  EKF_POS_VERT_AGL = 64,
  /// <remarks>
  /// EKF is in constant position mode and does not know it's absolute or relative position.
  /// </remarks>
  /// <summary>EKF_CONST_POS_MODE</summary>
  EKF_CONST_POS_MODE = 128,
  /// <remarks>
  /// Set if EKF's predicted horizontal position (relative) estimate is good.
  /// </remarks>
  /// <summary>EKF_PRED_POS_HORIZ_REL</summary>
  EKF_PRED_POS_HORIZ_REL = 256,
  /// <remarks>
  /// Set if EKF's predicted horizontal position (absolute) estimate is good.
  /// </remarks>
  /// <summary>EKF_PRED_POS_HORIZ_ABS</summary>
  EKF_PRED_POS_HORIZ_ABS = 512,
  /// <remarks>
  /// Set if EKF has never been healthy.
  /// </remarks>
  /// <summary>EKF_UNINITIALIZED</summary>
  EKF_UNINITIALIZED = 1024
}

public static class EkfStatusFlagsExtensions {
  public static EkfStatusFlags FromValue(int value) {
    foreach (var member in Enum.GetValues<EkfStatusFlags>()) {
      if ((int)member == value) {
        return member;
      }
    }
    var sorted = Enum.GetValues<EkfStatusFlags>().Where(m => (int)m > 0).OrderByDescending(m => (int)m);
    foreach (var member in sorted) {
      if ((value & (int)member) != 0) {
        return member;
      }
    }
    foreach (var member in Enum.GetValues<EkfStatusFlags>()) {
      if ((int)member == 0) {
        return member;
      }
    }
    return Enum.GetValues<EkfStatusFlags>()[0];
  }
}

