/// <remarks>
/// The heartbeat message shows that a system or component is present and responding. The type and autopilot fields (along with the message component id), allow the receiving system to treat further messages from this system appropriately (e.g. by laying out the user interface based on the autopilot). This microservice is documented at https://mavlink.io/en/services/heartbeat.html
/// </remarks>
/// <summary>HEARTBEAT</summary>
public sealed class Heartbeat : MavlinkMessage {
  public const int MsgId = 0;
  public const int CrcExtra = 50;
  public const int MavlinkEncodedLength = 9;

  public override int MavlinkMessageId => MsgId;
  public override int MavlinkCrcExtra => CrcExtra;


  /// <remarks>
  /// A bitfield for use for autopilot-specific flags
  /// </remarks>
  /// <summary>MAVLink type: uint32_t</summary>
  /// <summary>custom_mode</summary>
  public uint CustomMode { get; init; }

  /// <remarks>
  /// Vehicle or component type. For a flight controller component the vehicle type (quadrotor, helicopter, etc.). For other components the component type (e.g. camera, gimbal, etc.). This should be used in preference to component id for identifying the component type.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [MavType]</summary>
  /// <summary>type</summary>
  public MavType Type { get; init; }

  /// <remarks>
  /// Autopilot type / class. Use MAV_AUTOPILOT_INVALID for components that are not flight controllers.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [MavAutopilot]</summary>
  /// <summary>autopilot</summary>
  public MavAutopilot Autopilot { get; init; }

  /// <remarks>
  /// System mode bitmap.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [MavModeFlag]</summary>
  /// <summary>base_mode</summary>
  public byte BaseMode { get; init; }

  /// <remarks>
  /// System status flag.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [MavState]</summary>
  /// <summary>system_status</summary>
  public MavState SystemStatus { get; init; }

  /// <remarks>
