    return new OpticalFlowRad(
      TimeUsec: TimeUsec,
      IntegrationTimeUs: IntegrationTimeUs,
      IntegratedX: IntegratedX,
      IntegratedY: IntegratedY,
      IntegratedXgyro: IntegratedXgyro,
