    MavlinkMessage.SetFloat32(data, 12, AltitudeAmsl);
    MavlinkMessage.SetFloat32(data, 16, AltitudeLocal);
    MavlinkMessage.SetFloat32(data, 20, AltitudeRelative);
    MavlinkMessage.SetFloat32(data, 24, AltitudeTerrain);
    MavlinkMessage.SetFloat32(data, 28, BottomClearance);
