    MavlinkMessage.SetInt32(data, 20, Lon);
    MavlinkMessage.SetFloat32(data, 24, Alt);
    MavlinkMessage.SetFloat32List(data, 28, Vel);
    MavlinkMessage.SetFloat32List(data, 40, Acc);
    MavlinkMessage.SetFloat32List(data, 52, AttitudeQ);
    MavlinkMessage.SetFloat32List(data, 68, Rates);
    MavlinkMessage.SetFloat32List(data, 80, PositionCov);
    MavlinkMessage.SetUint8(data, 92, EstCapabilities);
    return data;
  }
}

