    var Z = MavlinkMessage.GetFloat32(data, 38);
    var Q = MavlinkMessage.GetFloat32List(data, 42, 4);
    var TypeRaw = MavlinkMessage.GetUint8(data, 58);
    var Type = LandingTargetTypeExtensions.FromValue((int)TypeRaw);
    var PositionValid = MavlinkMessage.GetUint8(data, 59);

