      TimeUsec: TimeUsec,
      AngleX: AngleX,
      AngleY: AngleY,
      Distance: Distance,
      SizeX: SizeX,
      SizeY: SizeY,
      TargetNum: TargetNum,
      Frame: Frame,
      X: X,
      Y: Y,
      Z: Z,
      Q: Q,
