/// <remarks>
/// Status of geo-fencing. Sent in extended status stream when fencing enabled.
/// </remarks>
/// <summary>FENCE_STATUS</summary>
public sealed class FenceStatus : MavlinkMessage {
  public const int MsgId = 162;
  public const int CrcExtra = 189;
  public const int MavlinkEncodedLength = 9;

  public override int MavlinkMessageId => MsgId;
  public override int MavlinkCrcExtra => CrcExtra;


  /// <remarks>
  /// Time (since boot) of last breach.
  /// </remarks>
  /// <summary>MAVLink type: uint32_t</summary>
  /// <summary>units: ms</summary>
  /// <summary>breach_time</summary>
  public uint BreachTime { get; init; }

  /// <remarks>
  /// Number of fence breaches.
  /// </remarks>
  /// <summary>MAVLink type: uint16_t</summary>
  /// <summary>breach_count</summary>
  public ushort BreachCount { get; init; }

  /// <remarks>
  /// Breach status (0 if currently inside fence, 1 if outside).
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>breach_status</summary>
  public byte BreachStatus { get; init; }

  /// <remarks>
  /// Last breach type.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [FenceBreach]</summary>
  /// <summary>breach_type</summary>
  public FenceBreach BreachType { get; init; }

  /// <remarks>
  /// Active action to prevent fence breach
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [FenceMitigate]</summary>
  /// <summary>Extensions field for MAVLink 2.</summary>
  /// <summary>breach_mitigation</summary>
  public FenceMitigate BreachMitigation { get; init; }

  public FenceStatus(uint BreachTime, ushort BreachCount, byte BreachStatus, FenceBreach BreachType, FenceMitigate BreachMitigation) {
    BreachTime = BreachTime;
    BreachCount = BreachCount;
    BreachStatus = BreachStatus;
    BreachType = BreachType;
    BreachMitigation = BreachMitigation;
  }

  public static FenceStatus Parse(ReadOnlySpan<byte> data) {
    if (data.Length < MavlinkEncodedLength) {
      data = PadPayload(data, MavlinkEncodedLength);
    }
    var BreachTime = MavlinkMessage.GetUint32(data, 0);
    var BreachCount = MavlinkMessage.GetUint16(data, 4);
    var BreachStatus = MavlinkMessage.GetUint8(data, 6);
    var BreachTypeRaw = MavlinkMessage.GetUint8(data, 7);
    var BreachType = FenceBreachExtensions.FromValue((int)BreachTypeRaw);
    var BreachMitigationRaw = MavlinkMessage.GetUint8(data, 8);
    var BreachMitigation = FenceMitigateExtensions.FromValue((int)BreachMitigationRaw);

    return new FenceStatus(
      BreachTime: BreachTime,
      BreachCount: BreachCount,
      BreachStatus: BreachStatus,
      BreachType: BreachType,
      BreachMitigation: BreachMitigation
    );
  }

  public override byte[] Serialize() {
    var data = new byte[MavlinkEncodedLength];
    MavlinkMessage.SetUint32(data, 0, BreachTime);
    MavlinkMessage.SetUint16(data, 4, BreachCount);
    MavlinkMessage.SetUint8(data, 6, BreachStatus);
    MavlinkMessage.SetUint8(data, 7, (byte)(int)BreachType);
    MavlinkMessage.SetUint8(data, 8, (byte)(int)BreachMitigation);
    return data;
  }
}

