/// <remarks>
/// RTCM message for injecting into the onboard GPS (used for DGPS)
/// </remarks>
/// <summary>GPS_RTCM_DATA</summary>
public sealed class GpsRtcmData : MavlinkMessage {
  public const int MsgId = 233;
  public const int CrcExtra = 35;
  public const int MavlinkEncodedLength = 182;

  public override int MavlinkMessageId => MsgId;
  public override int MavlinkCrcExtra => CrcExtra;


  /// <remarks>
  /// LSB: 1 means message is fragmented, next 2 bits are the fragment ID, the remaining 5 bits are used for the sequence ID. Messages are only to be flushed to the GPS when the entire message has been reconstructed on the autopilot. The fragment ID specifies which order the fragments should be assembled into a buffer, while the sequence ID is used to detect a mismatch between different buffers. The buffer is considered fully reconstructed when either all 4 fragments are present, or all the fragments before the first fragment with a non full payload is received. This management is used to ensure that normal GPS operation doesn't corrupt RTCM data, and to recover from a unreliable transport delivery order.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>flags</summary>
  public byte Flags { get; init; }

  /// <remarks>
  /// data length
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>units: bytes</summary>
  /// <summary>len</summary>
  public byte Len { get; init; }

  /// <remarks>
  /// RTCM message (may be fragmented)
  /// </remarks>
  /// <summary>MAVLink type: uint8_t[180]</summary>
  /// <summary>data</summary>
  public byte[] Data { get; init; }

  public GpsRtcmData(byte Flags, byte Len, byte[] Data) {
    Flags = Flags;
    Len = Len;
    Data = Data;
  }

  public static GpsRtcmData Parse(ReadOnlySpan<byte> data) {
    if (data.Length < MavlinkEncodedLength) {
      data = PadPayload(data, MavlinkEncodedLength);
    }
    var Flags = MavlinkMessage.GetUint8(data, 0);
    var Len = MavlinkMessage.GetUint8(data, 1);
    var Data = MavlinkMessage.GetUint8List(data, 2, 180);

    return new GpsRtcmData(
      Flags: Flags,
      Len: Len,
      Data: Data
    );
  }

  public override byte[] Serialize() {
    var data = new byte[MavlinkEncodedLength];
    MavlinkMessage.SetUint8(data, 0, Flags);
    MavlinkMessage.SetUint8(data, 1, Len);
    MavlinkMessage.SetUint8List(data, 2, Data);
    return data;
  }
}

