/// Status text message. These messages are printed in yellow in the COMM console of QGroundControl. WARNING: They consume quite some bandwidth, so use only for important status and error messages. If implemented wisely, these messages are buffered on the MCU and sent only at a limited rate (e.g. 10 Hz).
/// </remarks>
/// <summary>STATUSTEXT</summary>
public sealed class Statustext : MavlinkMessage {
  public const int MsgId = 253;
  public const int CrcExtra = 83;
  public const int MavlinkEncodedLength = 54;

  public override int MavlinkMessageId => MsgId;
  public override int MavlinkCrcExtra => CrcExtra;


  /// <remarks>
  /// Severity of status. Relies on the definitions within RFC-5424.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>enum: [MavSeverity]</summary>
  /// <summary>severity</summary>
  public MavSeverity Severity { get; init; }

  /// <remarks>
  /// Status text message, without null termination character
  /// </remarks>
  /// <summary>MAVLink type: char[50]</summary>
  /// <summary>text</summary>
  public byte[] Text { get; init; }

  /// <remarks>
  /// Unique (opaque) identifier for this statustext message.  May be used to reassemble a logical long-statustext message from a sequence of chunks.  A value of zero indicates this is the only chunk in the sequence and the message can be emitted immediately.
  /// </remarks>
  /// <summary>MAVLink type: uint16_t</summary>
  /// <summary>Extensions field for MAVLink 2.</summary>
  /// <summary>id</summary>
  public ushort Id { get; init; }

  /// <remarks>
  /// This chunk's sequence number; indexing is from zero.  Any null character in the text field is taken to mean this was the last chunk.
  /// </remarks>
  /// <summary>MAVLink type: uint8_t</summary>
  /// <summary>Extensions field for MAVLink 2.</summary>
  /// <summary>chunk_seq</summary>
  public byte ChunkSeq { get; init; }

  public Statustext(MavSeverity Severity, byte[] Text, ushort Id, byte ChunkSeq) {
    Severity = Severity;
    Text = Text;
    Id = Id;
    ChunkSeq = ChunkSeq;
  }

  public static Statustext Parse(ReadOnlySpan<byte> data) {
    if (data.Length < MavlinkEncodedLength) {
      data = PadPayload(data, MavlinkEncodedLength);
    }
    var SeverityRaw = MavlinkMessage.GetUint8(data, 0);
    var Severity = MavSeverityExtensions.FromValue((int)SeverityRaw);
    var Text = MavlinkMessage.GetUint8List(data, 1, 50);
    var Id = MavlinkMessage.GetUint16(data, 51);
    var ChunkSeq = MavlinkMessage.GetUint8(data, 53);

    return new Statustext(
      Severity: Severity,
      Text: Text,
      Id: Id,
      ChunkSeq: ChunkSeq
    );
  }

  public override byte[] Serialize() {
    var data = new byte[MavlinkEncodedLength];
    MavlinkMessage.SetUint8(data, 0, (byte)(int)Severity);
    MavlinkMessage.SetUint8List(data, 1, Text);
    MavlinkMessage.SetUint16(data, 51, Id);
    MavlinkMessage.SetUint8(data, 53, ChunkSeq);
    return data;
  }
}

