  /// <summary>angular_velocity_x</summary>
  public float AngularVelocityX { get; init; }

  /// <remarks>
  /// Y component of angular velocity (positive: pitching up). The frame is described in the message description. NaN if unknown.
  /// </remarks>
  /// <summary>MAVLink type: float</summary>
  /// <summary>units: rad/s</summary>
  /// <summary>angular_velocity_y</summary>
  public float AngularVelocityY { get; init; }

  /// <remarks>
