    MavlinkMessage.SetUint32(data, 4, LastAction);
    MavlinkMessage.SetUint32(data, 8, LastRecovery);
    MavlinkMessage.SetUint32(data, 12, LastClear);
    MavlinkMessage.SetUint16(data, 16, BreachCount);
    MavlinkMessage.SetUint8(data, 18, (byte)(int)LimitsState);
    MavlinkMessage.SetUint8(data, 19, (byte)(int)ModsEnabled);
    MavlinkMessage.SetUint8(data, 20, (byte)(int)ModsRequired);
    MavlinkMessage.SetUint8(data, 21, (byte)(int)ModsTriggered);
    return data;
  }
}

