    var TargetSystem = MavlinkMessage.GetUint8(data, 14);
    var TargetComponent = MavlinkMessage.GetUint8(data, 15);
    var Idx = MavlinkMessage.GetUint8(data, 16);
    var Count = MavlinkMessage.GetUint8(data, 17);
