  /// <summary>target_component</summary>
  public byte TargetComponent { get; init; }

  public RtRcCommandCancel(MavCmd Command, byte TargetSystem, byte TargetComponent) {
    Command = Command;
    TargetSystem = TargetSystem;
    TargetComponent = TargetComponent;
  }

  public static RtRcCommandCancel Parse(ReadOnlySpan<byte> data) {
    if (data.Length < MavlinkEncodedLength) {
      data = PadPayload(data, MavlinkEncodedLength);
    }
    var CommandRaw = MavlinkMessage.GetUint16(data, 0);
    var Command = MavCmdExtensions.FromValue((int)CommandRaw);
    var TargetSystem = MavlinkMessage.GetUint8(data, 2);
    var TargetComponent = MavlinkMessage.GetUint8(data, 3);

    return new RtRcCommandCancel(
      Command: Command,
      TargetSystem: TargetSystem,
      TargetComponent: TargetComponent
    );
  }

  public override byte[] Serialize() {
    var data = new byte[MavlinkEncodedLength];
    MavlinkMessage.SetUint16(data, 0, (ushort)(int)Command);
    MavlinkMessage.SetUint8(data, 2, TargetSystem);
    MavlinkMessage.SetUint8(data, 3, TargetComponent);
    return data;
  }
}

